import React, { useState } from 'react';
import { Link, useNavigate } from 'react-router-dom';
import { useAuth } from '../contexts/AuthContext';
import axios from 'axios';
import './Login.css';

const API_URL = process.env.REACT_APP_API_URL || 'http://localhost:5000/api';

const Login = () => {
  const [email, setEmail] = useState('');
  const [password, setPassword] = useState('');
  const [loading, setLoading] = useState(false);
  const [localError, setLocalError] = useState('');
  const [showForgotPassword, setShowForgotPassword] = useState(false);
  const [resetEmail, setResetEmail] = useState('');
  const [resetLoading, setResetLoading] = useState(false);
  const [resetMessage, setResetMessage] = useState('');
  const [resetError, setResetError] = useState('');
  const { login, error: authError } = useAuth();
  const navigate = useNavigate();

  const handleSubmit = async (e) => {
    e.preventDefault();
    setLoading(true);
    setLocalError('');
    
    if (!email || !password) {
      setLocalError('Please enter both email and password');
      setLoading(false);
      return;
    }
    
    const result = await login(email, password);
    
    if (!result.success) {
      setLocalError(result.error);
    }
    
    setLoading(false);
  };

  const handleForgotPassword = async (e) => {
    e.preventDefault();
    if (!resetEmail) {
      setResetError('Please enter your email address');
      return;
    }

    setResetLoading(true);
    setResetError('');
    setResetMessage('');

    try {
      const response = await axios.post(`${API_URL}/auth/forgot-password`, {
        email: resetEmail
      });
      
      setResetMessage(response.data.message || 'Password reset link has been sent to your email');
      setTimeout(() => {
        setShowForgotPassword(false);
        setResetEmail('');
        setResetMessage('');
      }, 3000);
    } catch (error) {
      setResetError(error.response?.data?.error || 'Failed to send reset link. Please try again.');
    } finally {
      setResetLoading(false);
    }
  };

  const displayError = localError || authError;

  return (
    <div className="login-container">
      <div className="login-card">
        <div className="login-header">
          <h1 className="login-title">
            AGRIVEND
          </h1>
          <p className="login-subtitle">
            Administrator Portal
          </p>
        </div>
        
        {displayError && (
          <div className="login-error">
            {displayError}
          </div>
        )}
        
        {!showForgotPassword ? (
          <form className="login-form" onSubmit={handleSubmit}>
            <div className="form-group">
              <label className="form-label">
                Email Address
              </label>
              <input
                type="email"
                required
                value={email}
                onChange={(e) => setEmail(e.target.value)}
                placeholder="admin@agrivend.com"
                className="form-input"
                disabled={loading}
              />
            </div>
            
            <div className="form-group">
              <label className="form-label">
                Password
              </label>
              <input
                type="password"
                required
                value={password}
                onChange={(e) => setPassword(e.target.value)}
                placeholder="Enter your password"
                className="form-input"
                disabled={loading}
              />
            </div>

            <div className="form-options">
              <button
                type="button"
                onClick={() => setShowForgotPassword(true)}
                className="forgot-password-link"
              >
                Forgot Password?
              </button>
            </div>

            <button
              type="submit"
              disabled={loading}
              className={`login-button ${loading ? 'loading' : ''}`}
            >
              {loading ? 'Signing in...' : 'Sign In'}
            </button>
          </form>
        ) : (
          <form className="login-form" onSubmit={handleForgotPassword}>
            <div className="form-group">
              <label className="form-label">
                Email Address
              </label>
              <input
                type="email"
                required
                value={resetEmail}
                onChange={(e) => setResetEmail(e.target.value)}
                placeholder="Enter your registered email"
                className="form-input"
                disabled={resetLoading}
              />
            </div>

            {resetError && (
              <div className="reset-error">
                {resetError}
              </div>
            )}

            {resetMessage && (
              <div className="reset-success">
                {resetMessage}
              </div>
            )}

            <div className="form-actions">
              <button
                type="submit"
                disabled={resetLoading}
                className={`login-button ${resetLoading ? 'loading' : ''}`}
              >
                {resetLoading ? 'Sending...' : 'Send Reset Link'}
              </button>
              
              <button
                type="button"
                onClick={() => {
                  setShowForgotPassword(false);
                  setResetError('');
                  setResetMessage('');
                  setResetEmail('');
                }}
                className="back-to-login"
              >
                Back to Login
              </button>
            </div>
          </form>
        )}

        <div className="demo-credentials">
          <div className="demo-badge">Demo Credentials</div>
          <div className="demo-info">
            <div className="demo-row">
              <span className="demo-label">Admin Email:</span>
              <span className="demo-value">admin@agrivend.com</span>
            </div>
            <div className="demo-row">
              <span className="demo-label">Password:</span>
              <span className="demo-value">admin123</span>
            </div>
          </div>
        </div>
      </div>
    </div>
  );
};

export default Login;
